def load_payloads(filepath):
    with open(filepath, "r", encoding="utf-8") as f:
        data = json.load(f)
    if isinstance(data, list): return data
    if isinstance(data, dict) and "payloads" in data: return data["payloads"]
    raise ValueError("载荷文件格式错误")
